```class Solution {
    public int countWinningSequences(String s) {
        int MOD = 1000000007;
        int n = s.length();
        int[] dp = new int[n + 1];
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            if (s.charAt(i - 1) == 'F') {
                dp[i] = (dp[i - 1] + dp[i - 2]) % MOD;
            } else if (s.charAt(i - 1) == 'W') {
                dp[i] = (dp[i - 1] + dp[i - 3]) % MOD;
            } else {
                dp[i] = (dp[i - 1] + dp[i - 2] + dp[i - 3]) % MOD;
            }
        }
        return dp[n];
    }
}```
